// Request Validator - Single source of truth for API key and store name
  const input = $input.item.json || {};

  // Extract from body if exists (webhook format)
  const body = input.body || input;
  const chatInput = body.chatInput;
  const sessionId = body.sessionId;

  // ============================================
  // CONFIGURATION - Change values here
  // ============================================
  const GEMINI_API_KEY = "AIzaSyAmi8rLTrz3JCQZ2JoBgGSzOtXO_MDgUk8";
  const FILE_SEARCH_STORE = "fileSearchStores/n8ndocumentsstore-f7cqp3cqctc6";
  // ============================================

  // Validation - check required fields
  if (!chatInput || typeof chatInput !== 'string') {
    return [{
      json: {
        error: true,
        message: "Missing or invalid 'chatInput' field. Please provide a valid message.",
        statusCode: 400,
        timestamp: new Date().toISOString()
      }
    }];
  }

  if (!sessionId || typeof sessionId !== 'string') {
    return [{
      json: {
        error: true,
        message: "Missing or invalid 'sessionId' field. Please provide a session identifier.",
        statusCode: 400,
        timestamp: new Date().toISOString()
      }
    }];
  }

  // Return validated and cleaned data with configuration
  return [{
    json: {
      chatInput: chatInput.trim(),
      sessionId: sessionId,
      store_name: FILE_SEARCH_STORE,
      api_key: GEMINI_API_KEY,
      timestamp: new Date().toISOString(),
      validated: true
    }
  }];

// Prepare Agent Input - Merge conversation context with current query
  const data = $json;
  let enhancedPrompt = data.chatInput;
  let originalQuery = data.chatInput;

  // If conversation history exists, add context
  if (data.hasHistory && data.conversationHistory?.messages?.length > 0) {
    const recentMessages = data.conversationHistory.messages.slice(-5);
    const context = recentMessages
      .map(m => `${m.role === 'user' ? 'Pengguna' : 'Asisten'}: ${m.content}`)
      .join('\n');

    enhancedPrompt = `KONTEKS PERCAKAPANAN SEBELUMNYA:\n${context}\n\nPERTANYAAN SAAT INI:\n${data.chatInput}`;
  }

  // Pass through all data including api_key and store_name
  return [{
    json: {
      chatInput: enhancedPrompt,
      originalQuery: originalQuery,
      sessionId: data.sessionId,
      store_name: data.store_name,
      api_key: data.api_key,
      timestamp: data.timestamp,
      validated: data.validated
