={
  "systemInstruction": {
    "parts": [
      {
        "text": "RETRIEVAL ONLY MODE. You are a document search engine. 1. Search the attached files for information matching the query. 2. Return ONLY the relevant excerpts, facts, and source filenames. 3. Do not offer chatty greetings or filler. 4. If no information is found, output 'NO_DATA_FOUND'."
      }
    ]
  },
  "contents": [
    {
      "parts": [
        {
          "text": "{{ $json.query || $('Request Validator').item.json.chatInput }}" 
        }
      ]
    }
  ],
  "tools": [
    {
      "fileSearch": {
        "fileSearchStoreNames": [
          "{{ $json.store_name }}"
        ]
      }
    }
  ],
  "generationConfig": {
    "temperature": 0.0,
    "maxOutputTokens": 2048
  }
}
